 {"id":"bd-k5q5.9.2.3","title":"[LISR-2.3] Implement confidence scoring model with explainable signals","description":"Compute legibility confidence using weighted deterministic signals and explicit penalties for ambiguity/risk indicators.","design":"Output score plus per-signal contributions so operators and tests can explain every gating outcome.","acceptance_criteria":"Confidence computation is deterministic, calibrated on fixtures, and stable across runs.","notes":"Explainability is mandatory for trust and policy review.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:34.843263213Z","created_by":"ubuntu","updated_at":"2026-02-08T21:32:59.690145800Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","intent","lisr","repair","scoring"],"dependencies":[{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2","type":"parent-child","created_at":"2026-02-08T21:32:34.843263213Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2.1","type":"blocks","created_at":"2026-02-08T21:32:59.407851300Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.3","depends_on_id":"bd-k5q5.9.2.2","type":"blocks","created_at":"2026-02-08T21:32:59.690075239Z","created_by":"ubuntu"}]}
 {"id":"bd-k5q5.9.2.4","title":"[LISR-2.4] Implement gating decision API and reason-code contract","description":"Expose allow/suggest/deny gating API with structured reason codes and remediation guidance for denied cases.","design":"Integrate with policy modes so gate outcomes are actionable and composable with downstream repair strategy.","acceptance_criteria":"All non-allow decisions include machine-readable reasons, human-readable explanation, and suggested next steps.","notes":"This becomes the canonical control handoff from analysis to repair.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-08T21:32:35.780726484Z","created_by":"ubuntu","updated_at":"2026-02-08T21:32:59.983288812Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["extensions","gating","intent","lisr","repair"],"dependencies":[{"issue_id":"bd-k5q5.9.2.4","depends_on_id":"bd-k5q5.9.2","type":"parent-child","created_at":"2026-02-08T21:32:35.780726484Z","created_by":"ubuntu"},{"issue_id":"bd-k5q5.9.2.4","depends_on_id":"bd-k5q5.9.2.3","type":"blocks","created_at":"2026-02-08T21:32:59.983239760Z","created_by":"ubuntu"}]}
